(window.webpackJsonp=window.webpackJsonp||[]).push([[1094],{1389:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code>\\n<span class=\\"hljs-keyword\\">var</span> MyCalendar = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.range=[]\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number} start \\n * @param {number} end\\n * @return {boolean}\\n */</span>\\nMyCalendar.prototype.book = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">start, end</span>) </span>{\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;<span class=\\"hljs-keyword\\">this</span>.range.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> itv=<span class=\\"hljs-keyword\\">this</span>.range[i]\\n    <span class=\\"hljs-keyword\\">if</span>(start &lt; itv[<span class=\\"hljs-number\\">1</span>] &amp;&amp; end &gt; itv[<span class=\\"hljs-number\\">0</span>])<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.range.push([start,end])\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * Your MyCalendar object will be instantiated and called as such:\\n * var obj = Object.create(MyCalendar).createNew()\\n * var param_1 = obj.book(start,end)\\n */</span>\\n</code></pre>\\n"],"titleSlug":"my-calendar-i","hasThinking":false,"content":"<p>\u5b9e\u73b0\u4e00\u4e2a <code>MyCalendar</code> \u7c7b\u6765\u5b58\u653e\u4f60\u7684\u65e5\u7a0b\u5b89\u6392\u3002\u5982\u679c\u8981\u6dfb\u52a0\u7684\u65f6\u95f4\u5185\u6ca1\u6709\u5176\u4ed6\u5b89\u6392\uff0c\u5219\u53ef\u4ee5\u5b58\u50a8\u8fd9\u4e2a\u65b0\u7684\u65e5\u7a0b\u5b89\u6392\u3002</p>\\n\\n<p><code>MyCalendar</code> \u6709\u4e00\u4e2a <code>book(int start, int end)</code>\u65b9\u6cd5\u3002\u5b83\u610f\u5473\u7740\u5728 start \u5230 end \u65f6\u95f4\u5185\u589e\u52a0\u4e00\u4e2a\u65e5\u7a0b\u5b89\u6392\uff0c\u6ce8\u610f\uff0c\u8fd9\u91cc\u7684\u65f6\u95f4\u662f\u534a\u5f00\u533a\u95f4\uff0c\u5373 <code>[start, end)</code>, \u5b9e\u6570\xa0<code>x</code> \u7684\u8303\u56f4\u4e3a\uff0c \xa0<code>start <= x < end</code>\u3002</p>\\n\\n<p>\u5f53\u4e24\u4e2a\u65e5\u7a0b\u5b89\u6392\u6709\u4e00\u4e9b\u65f6\u95f4\u4e0a\u7684\u4ea4\u53c9\u65f6\uff08\u4f8b\u5982\u4e24\u4e2a\u65e5\u7a0b\u5b89\u6392\u90fd\u5728\u540c\u4e00\u65f6\u95f4\u5185\uff09\uff0c\u5c31\u4f1a\u4ea7\u751f\u91cd\u590d\u9884\u8ba2\u3002</p>\\n\\n<p>\u6bcf\u6b21\u8c03\u7528 <code>MyCalendar.book</code>\u65b9\u6cd5\u65f6\uff0c\u5982\u679c\u53ef\u4ee5\u5c06\u65e5\u7a0b\u5b89\u6392\u6210\u529f\u6dfb\u52a0\u5230\u65e5\u5386\u4e2d\u800c\u4e0d\u4f1a\u5bfc\u81f4\u91cd\u590d\u9884\u8ba2\uff0c\u8fd4\u56de <code>true</code>\u3002\u5426\u5219\uff0c\u8fd4\u56de <code>false</code>\xa0\u5e76\u4e14\u4e0d\u8981\u5c06\u8be5\u65e5\u7a0b\u5b89\u6392\u6dfb\u52a0\u5230\u65e5\u5386\u4e2d\u3002</p>\\n\\n<p>\u8bf7\u6309\u7167\u4ee5\u4e0b\u6b65\u9aa4\u8c03\u7528 <code>MyCalendar</code> \u7c7b: <code>MyCalendar cal = new MyCalendar();</code> <code>MyCalendar.book(start, end)</code></p>\\n\\n<p><strong>\u793a\u4f8b 1:</strong></p>\\n\\n<pre>\\nMyCalendar();\\nMyCalendar.book(10, 20); // returns true\\nMyCalendar.book(15, 25); // returns false\\nMyCalendar.book(20, 30); // returns true\\n<strong>\u89e3\u91ca:</strong> \\n\u7b2c\u4e00\u4e2a\u65e5\u7a0b\u5b89\u6392\u53ef\u4ee5\u6dfb\u52a0\u5230\u65e5\u5386\u4e2d.  \u7b2c\u4e8c\u4e2a\u65e5\u7a0b\u5b89\u6392\u4e0d\u80fd\u6dfb\u52a0\u5230\u65e5\u5386\u4e2d\uff0c\u56e0\u4e3a\u65f6\u95f4 15 \u5df2\u7ecf\u88ab\u7b2c\u4e00\u4e2a\u65e5\u7a0b\u5b89\u6392\u9884\u5b9a\u4e86\u3002\\n\u7b2c\u4e09\u4e2a\u65e5\u7a0b\u5b89\u6392\u53ef\u4ee5\u6dfb\u52a0\u5230\u65e5\u5386\u4e2d\uff0c\u56e0\u4e3a\u7b2c\u4e00\u4e2a\u65e5\u7a0b\u5b89\u6392\u5e76\u4e0d\u5305\u542b\u65f6\u95f4 20 \u3002\\n</pre>\\n\\n<p><strong>\u8bf4\u660e:</strong></p>\\n\\n<ul>\\n\\t<li>\u6bcf\u4e2a\u6d4b\u8bd5\u7528\u4f8b\uff0c\u8c03\u7528\xa0<code>MyCalendar.book</code>\xa0\u51fd\u6570\u6700\u591a\u4e0d\u8d85\u8fc7\xa0<code>1000</code>\u6b21\u3002</li>\\n\\t<li>\u8c03\u7528\u51fd\u6570\xa0<code>MyCalendar.book(start, end)</code>\u65f6\uff0c\xa0<code>start</code> \u548c\xa0<code>end</code> \u7684\u53d6\u503c\u8303\u56f4\u4e3a\xa0<code>[0, 10^9]</code>\u3002</li>\\n</ul>\\n","title":"729. \u6211\u7684\u65e5\u7a0b\u5b89\u6392\u8868 I","relatedTags":["\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"729"}')}}]);